record ProductRequest(
    @NotBlank(message="Name required") @Size(max=200) String name,
    @NotNull @Positive(message="Price must be positive") Double price,
    @NotBlank(message="Category required") String category,
    @Min(0) @Max(9999) int stockQty
) {}
// Product @Entity (as in T13.3)
