// ProductService:
@Service @Transactional
class ProductService {
    private final ProductRepository repo;
    ProductService(ProductRepository r) { repo=r; }
    Product create(ProductRequest req) {
        if (repo.existsByName(req.name())) throw new DuplicateResourceException("Exists: "+req.name());
        return repo.save(new Product(req.name(), req.price(), req.category(), req.stockQty()));
    }
    Product findByIdOrThrow(String id) {
        return repo.findById(id).orElseThrow(()->new ResourceNotFoundException("Product",id));
    }
    List<Product> findAll() { return repo.findAll(); }
    Product update(String id, ProductRequest req) { Product p=findByIdOrThrow(id); /* update fields */ return repo.save(p); }
    void delete(String id) { findByIdOrThrow(id); repo.deleteById(id); }
}
// ProductController:
@RestController @RequestMapping("/api/products")
class ProductController {
    private final ProductService service;
    ProductController(ProductService s) { service=s; }
    @GetMapping public List<Product> getAll() { return service.findAll(); }
    @GetMapping("/{id}") public Product getById(@PathVariable String id) { return service.findByIdOrThrow(id); }
    @PostMapping public ResponseEntity<Product> create(@Valid @RequestBody ProductRequest req) {
        return ResponseEntity.status(201).body(service.create(req)); }
    @DeleteMapping("/{id}") public ResponseEntity<Void> delete(@PathVariable String id) {
        service.delete(id); return ResponseEntity.noContent().build(); }
}
